-- steroidV2 Database Schema
-- Rebuilt from S4QL reference — no LOCK TABLES, InnoDB, utf8mb4, clean indexes
-- Generated by LARS for Steroid V2 Rebuild

SET FOREIGN_KEY_CHECKS = 0;
SET sql_mode = 'STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION';

-- blocks
CREATE TABLE IF NOT EXISTS `blocks` (
  `id`           varbinary(128)  NOT NULL,
  `generator`    varbinary(128)  NOT NULL,
  `height`       bigint(20)      NOT NULL,
  `date`         int(11)         NOT NULL,
  `nonce`        varbinary(128)  NOT NULL,
  `signature`    varbinary(256)  NOT NULL,
  `difficulty`   varchar(64)     COLLATE utf8mb4_bin NOT NULL,
  `argon`        varbinary(128)  NOT NULL,
  `transactions` int(11)         NOT NULL DEFAULT 0,
  PRIMARY KEY (`height`),
  UNIQUE KEY `uq_block_id`   (`id`),
  KEY `idx_generator`        (`generator`),
  KEY `idx_date`             (`date`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- accounts
CREATE TABLE IF NOT EXISTS `accounts` (
  `id`         varbinary(128)  NOT NULL,
  `public_key` varbinary(1024) NOT NULL,
  `block`      varbinary(128)  NOT NULL,
  `balance`    decimal(20,8)   NOT NULL DEFAULT 0.00000000,
  `alias`      varchar(32)     COLLATE utf8mb4_bin DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_block`  (`block`),
  KEY `idx_alias`  (`alias`),
  KEY `idx_pubkey` (`public_key`(767)),
  CONSTRAINT `fk_accounts_block`
    FOREIGN KEY (`block`) REFERENCES `blocks` (`id`)
    ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- transactions
CREATE TABLE IF NOT EXISTS `transactions` (
  `id`         varbinary(128)  NOT NULL,
  `block`      varbinary(128)  NOT NULL,
  `height`     bigint(20)      NOT NULL,
  `src`        varbinary(128)  NOT NULL,
  `dst`        varbinary(128)  NOT NULL,
  `val`        decimal(20,8)   NOT NULL DEFAULT 0.00000000,
  `fee`        decimal(20,8)   NOT NULL DEFAULT 0.00000000,
  `signature`  varbinary(256)  NOT NULL,
  `version`    tinyint(4)      NOT NULL DEFAULT 0,
  `message`    varchar(256)    COLLATE utf8mb4_bin DEFAULT '',
  `date`       int(11)         NOT NULL,
  `public_key` varbinary(1024) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_block`          (`block`),
  KEY `idx_height`         (`height`),
  KEY `idx_src`            (`src`),
  KEY `idx_dst`            (`dst`),
  KEY `idx_pubkey_height`  (`public_key`(130), `height`),
  KEY `idx_dst_height`     (`dst`, `height`),
  KEY `idx_version_height` (`version`, `height`),
  CONSTRAINT `fk_tx_height`
    FOREIGN KEY (`height`) REFERENCES `blocks` (`height`)
    ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- mempool
CREATE TABLE IF NOT EXISTS `mempool` (
  `id`         varbinary(128)  NOT NULL,
  `height`     bigint(20)      NOT NULL,
  `src`        varbinary(128)  NOT NULL,
  `dst`        varbinary(128)  NOT NULL,
  `val`        decimal(20,8)   NOT NULL DEFAULT 0.00000000,
  `fee`        decimal(20,8)   NOT NULL DEFAULT 0.00000000,
  `signature`  varbinary(256)  NOT NULL,
  `version`    tinyint(4)      NOT NULL,
  `message`    varchar(256)    COLLATE utf8mb4_bin DEFAULT '',
  `public_key` varbinary(1024) NOT NULL,
  `date`       bigint(20)      NOT NULL,
  `peer`       varchar(64)     COLLATE utf8mb4_bin DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_height` (`height`),
  KEY `idx_src`    (`src`),
  KEY `idx_peer`   (`peer`),
  KEY `idx_val`    (`val`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- masternode
CREATE TABLE IF NOT EXISTS `masternode` (
  `public_key`    varbinary(512) NOT NULL,
  `height`        int(11)        NOT NULL,
  `ip`            varchar(16)    COLLATE utf8mb4_bin NOT NULL,
  `last_won`      int(11)        NOT NULL DEFAULT 0,
  `blacklist`     int(11)        NOT NULL DEFAULT 0,
  `fails`         int(11)        NOT NULL DEFAULT 0,
  `status`        tinyint(4)     NOT NULL DEFAULT 1,
  `vote_key`      varbinary(512) DEFAULT NULL,
  `cold_last_won` int(11)        NOT NULL DEFAULT 0,
  `voted`         tinyint(4)     NOT NULL DEFAULT 0,
  PRIMARY KEY (`public_key`),
  KEY `idx_last_won`      (`last_won`),
  KEY `idx_status`        (`status`),
  KEY `idx_blacklist`     (`blacklist`),
  KEY `idx_height`        (`height`),
  KEY `idx_vote_key`      (`vote_key`),
  KEY `idx_cold_last_won` (`cold_last_won`),
  KEY `idx_voted`         (`voted`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin;

