  `stat`    varchar(64)  COLLATE utf8mb4_bin NOT NULL,
  `val`     varchar(200) COLLATE utf8mb4_bin NOT NULL DEFAULT '',
  `updated` datetime     NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_stat` (`stat`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- blockstats view
CREATE OR REPLACE VIEW `blockstats` AS
  SELECT
    (a.`date` - b.`date`)   AS `blocktime`,
    a.`height`              AS `height`,
    a.`date`                AS `timestamp`,
    FROM_UNIXTIME(a.`date`) AS `date_time`,
    NOW()                   AS `currenttime`,
    a.`difficulty`          AS `difficulty`
  FROM `blocks` a
  LEFT JOIN `blocks` b ON b.`height` = (a.`height` - 1)
  ORDER BY a.`height` DESC
  LIMIT 100;

SET FOREIGN_KEY_CHECKS = 1;
